pragma solidity ^0.8.13;
import """"forge-std/Test.sol"""";
import """"../Bank.sol"""";

contract Dummy {}

contract BankTest is Test {
    address immutable bank_deployer;      // TODO check
    Bank immutable bank;

    constructor() {
        // deploying a Bank contract
        address bank_deployer = address(0xB0B);
        vm.prank(bank_deployer);
        bank = new Bank();
    }

    function test_deposit_additivity_violation() public {
        vm.deal(address(0xBEEF), 3);

        address sender = address(0xBEEF);
        uint256 snapshot = vm.snapshotState();

        address user = address(0xBEEF);

        uint256 n1 = 1;
        uint256 n2 = 2;

        vm.prank(sender);
        bank.deposit{value: n1}();
        vm.prank(sender);
        bank.deposit{value: n2}();


        uint256 credits_slot = uint256(0);
        bytes32 user_credits_slot = keccak256(abi.encode(user, credits_slot));
        uint256 user_credits_pathA = uint256(vm.load(address(bank), user_credits_slot));

        vm.revertToState(snapshot);

        vm.prank(sender);
        bank.deposit{value: n1+n2}();

        uint256 user_credits_pathB = uint256(vm.load(address(bank), user_credits_slot));

        assertNotEq(user_credits_pathB, user_credits_pathA, """"Credits are equal"""");
    }
}

raw_output:
ANSWER: FALSE
EXPLANATION: Each Bank.deposit call credits msg.sender by msg.value + 1. Two deposits of n1 and n2 give n1 + n2 + 2, while one deposit of n1 + n2 gives n1 + n2 + 1. Setting user = sender ensures user_credits_pathA != user_credits_pathB, so the assertion holds. The previous OutOfFunds error is fixed by funding the pranked sender via vm.deal before the snapshot.
